div.script:
    const TemplateApp = (() => {
      const $ = (q, el=document) => el.querySelector(q);
      const $$ = (q, el=document) => [...el.querySelectorAll(q)];
      const state = {
        preset: 'neon-corporate',
        density: 'comfortable',
        motion: true,
        activeSection: 'home',
        paletteOpen: false,
        quickViewOpen: false,
      };
      const content = {
        meta: { siteName: 'UNIVERSAL / SITE', tagline: 'A shape-shifting website system in one file.' },
        presets: {
          'neon-corporate': { brand: '#78a9ff', brand2: '#9a7cff', brand3: '#33d6a6', bg: '#070b16' },
          'editorial-luxe': { brand: '#d4b483', brand2: '#8c6dfd', brand3: '#ff7b7b', bg: '#120d0a' },
          'minimal-tech': { brand: '#91f0d1', brand2: '#6ea8fe', brand3: '#caa8ff', bg: '#061014' },
          'sunset-brand': { brand: '#ff9966', brand2: '#ff5e62', brand3: '#ffd166', bg: '#180d10' },
          'forest-product': { brand: '#6ee7b7', brand2: '#34d399', brand3: '#84cc16', bg: '#08110d' },
          'ice-startup': { brand: '#7dd3fc', brand2: '#60a5fa', brand3: '#c4b5fd', bg: '#07111a' },
          'mono-premium': { brand: '#f5f7ff', brand2: '#d0d7eb', brand3: '#9aa5bf', bg: '#090a0e' },
          'festival-pop': { brand: '#ff4ecd', brand2: '#ffb703', brand3: '#00d4ff', bg: '#12051a' },
          'earth-editorial': { brand: '#b08968', brand2: '#7f5539', brand3: '#ddb892', bg: '#16100d' },
          'future-saas': { brand: '#22d3ee', brand2: '#818cf8', brand3: '#34d399', bg: '#050816' },
          'signal-red': { brand: '#ff6b6b', brand2: '#f06595', brand3: '#ffd166', bg: '#160608' },
          'aurora-studio': { brand: '#2dd4bf', brand2: '#818cf8', brand3: '#f472b6', bg: '#071016' },
          'desert-ui': { brand: '#f59e0b', brand2: '#fb7185', brand3: '#fcd34d', bg: '#160f08' },
          'deep-space': { brand: '#60a5fa', brand2: '#a78bfa', brand3: '#4ade80', bg: '#030712' },
          'carbon-gold': { brand: '#f6e27a', brand2: '#d4af37', brand3: '#f59e0b', bg: '#0b0b0d' },
          'ocean-lab': { brand: '#38bdf8', brand2: '#22c55e', brand3: '#14b8a6', bg: '#041018' },
          'plasma-grid': { brand: '#a855f7', brand2: '#ec4899', brand3: '#06b6d4', bg: '#090312' },
          'artisan-soft': { brand: '#fca5a5', brand2: '#fdba74', brand3: '#fcd34d', bg: '#1b1111' },
        },
        commandGroups: [],
      };
      function setVar(name, value){ document.documentElement.style.setProperty(name, value); }
      function applyPreset(name){ const p = content.presets[name]; if(!p) return; setVar('--brand', p.brand); setVar('--brand-2', p.brand2); setVar('--brand-3', p.brand3); setVar('--bg', p.bg); state.preset = name; toast(`Preset switched to ${name}`); renderThemeOptions(); }
      function applyDensity(mode){ state.density = mode; const compact = mode === 'compact'; setVar('--grid', compact ? '18px' : mode === 'expanded' ? '30px' : '24px'); document.body.style.letterSpacing = compact ? '-.01em' : '0'; $$('.feature-card,.case-card,.pricing-card,.team-card,.blog-card,.testimonial-card,.contact-card,.faq-item,.footer-card,.panel').forEach(el => el.style.padding = compact ? '18px' : mode === 'expanded' ? '28px' : '24px'); toast(`Density set to ${mode}`); }
      function toggleMotion(force){ state.motion = typeof force === 'boolean' ? force : !state.motion; document.body.classList.toggle('motion-off', !state.motion); toast(`Motion ${state.motion ? 'enabled' : 'disabled'}`); }
      function reveal(){ const io = new IntersectionObserver(entries => { entries.forEach(entry => { if(entry.isIntersecting || !state.motion){ entry.target.classList.add('visible'); io.unobserve(entry.target);} }); }, { threshold: .12 }); $$('[data-reveal]').forEach(el => io.observe(el)); if(!state.motion) $$('[data-reveal]').forEach(el => el.classList.add('visible')); }
      function spyNav(){ const sections = $$('main section[id], main[id]'); const io = new IntersectionObserver(entries => { entries.forEach(e => { if(e.isIntersecting){ const id = e.target.id || 'home'; state.activeSection = id; $$('.nav-links a').forEach(a => a.classList.toggle('active', a.getAttribute('href') === '#' + id)); } }); }, { rootMargin: '-40% 0px -45% 0px', threshold: .01 }); sections.forEach(s => io.observe(s)); }
      function bindTilt(){ $$('[data-tilt]').forEach(card => { card.addEventListener('pointermove', e => { if(!state.motion) return; const r = card.getBoundingClientRect(); const x = (e.clientX - r.left) / r.width; const y = (e.clientY - r.top) / r.height; const rx = (0.5 - y) * 8; const ry = (x - 0.5) * 10; card.style.transform = `perspective(1200px) rotateX(${rx}deg) rotateY(${ry}deg) translateY(-2px)`; }); card.addEventListener('pointerleave', () => card.style.transform = ''); }); }
      function initCursorGlow(){ const glow = $('#cursorGlow'); window.addEventListener('pointermove', e => { glow.style.transform = `translate(${e.clientX}px, ${e.clientY}px)`; }); }
      function initNoise(){ const c = $('#noise'); const ctx = c.getContext('2d'); function resize(){ c.width = innerWidth * devicePixelRatio; c.height = innerHeight * devicePixelRatio; c.style.width = innerWidth + 'px'; c.style.height = innerHeight + 'px'; ctx.scale(devicePixelRatio, devicePixelRatio); } resize(); addEventListener('resize', resize); function draw(){ const w = innerWidth, h = innerHeight; const img = ctx.createImageData(w, h); const data = img.data; for(let i=0;i({ x:Math.random()*90, y:Math.random()*90, s:180+Math.random()*300, c:`var(--tone-${(i*17)%360+1})`, dx:(Math.random()-.5)*.05, dy:(Math.random()-.5)*.05 })); orbData.forEach(o=>{ const d=document.createElement('div'); d.className='spotlight'; d.style.width=o.s+'px'; d.style.height=o.s+'px'; d.style.left=o.x+'vw'; d.style.top=o.y+'vh'; d.style.background=`radial-gradient(circle, ${o.c}, transparent 70%)`; wrap.appendChild(d); o.el=d;}); function tick(){ orbData.forEach(o=>{ o.x += o.dx; o.y += o.dy; if(o.x< -10 || o.x>90) o.dx*=-1; if(o.y< -10 || o.y>90) o.dy*=-1; o.el.style.left=o.x+'vw'; o.el.style.top=o.y+'vh'; }); requestAnimationFrame(tick);} tick(); }
      function toast(message){ const stack = $('#toastStack'); const el = document.createElement('div'); el.className='toast'; el.textContent = message; stack.appendChild(el); setTimeout(()=>{ el.style.opacity='0'; el.style.transform='translateY(8px)'; }, 2600); setTimeout(()=>el.remove(), 3200); }
      function openQuickView(html){ $('#quickViewBody').innerHTML = html; $('#quickView').classList.add('active'); state.quickViewOpen = true; }
      function buildCommands(){
        const sectionCommands = $$('main section[id], main[id]').map(sec => ({ label:`Go to ${sec.id || 'home'}`, hint:'Jump', run:()=>location.hash='#'+(sec.id||'home') }));
        const presetCommands = Object.keys(content.presets).map(name => ({ label:`Switch preset: ${name}`, hint:'Theme', run:()=>applyPreset(name) }));
        const densityCommands = ['compact','comfortable','expanded'].map(name => ({ label:`Set density: ${name}`, hint:'Layout', run:()=>applyDensity(name) }));
        const actionCommands = [
          { label:'Toggle motion', hint:'Behavior', run:()=>toggleMotion() },
          { label:'Open theme drawer', hint:'UI', run:()=>toggleThemeDrawer(true) },
          { label:'Preview content schema', hint:'Data', run:()=>openQuickView(`${escapeHtml(JSON.stringify({site:content.meta,presets:Object.keys(content.presets),sections:$$('main section[id]').map(s=>s.id)}, null, 2))}`) },
          { label:'Generate demo toast', hint:'Feedback', run:()=>toast('System ready for customization.') },
          { label:'Highlight reusable modules', hint:'Visual', run:()=>$$('.feature-card,.case-card,.pricing-card').forEach((el,i)=>setTimeout(()=>{el.style.outline='1px solid rgba(255,255,255,.2)'; setTimeout(()=>el.style.outline='',900)}, i*40)) },
        ];
        content.commandGroups = [...sectionCommands, ...presetCommands, ...densityCommands, ...actionCommands];
      }
      function escapeHtml(s){ return String(s).replace(/[&<>"']/g, m => ({'&':'&','<':'<','>':'>','"':'"',"'":'''}[m])); }
      function renderPaletteResults(term=''){ const list = $('#paletteResults'); const t = term.trim().toLowerCase(); const items = content.commandGroups.filter(item => !t || item.label.toLowerCase().includes(t) || item.hint.toLowerCase().includes(t)); list.innerHTML=''; items.slice(0, 24).forEach((item, idx) => { const row = document.createElement('button'); row.className='palette-item'; row.type='button'; row.innerHTML=`${item.label}${item.hint}`; row.addEventListener('click', ()=>{ item.run(); togglePalette(false); }); if(idx===0) row.classList.add('active'); list.appendChild(row); }); }
      function togglePalette(force){ state.paletteOpen = typeof force === 'boolean' ? force : !state.paletteOpen; $('#commandPalette').classList.toggle('active', state.paletteOpen); $('#commandPalette').setAttribute('aria-hidden', String(!state.paletteOpen)); if(state.paletteOpen){ $('#paletteInput').value=''; renderPaletteResults(); setTimeout(()=>$('#paletteInput').focus(), 20); } }
      function renderThemeOptions(){ const root = $('#themeOptions'); if(!root) return; root.innerHTML = ''; Object.entries(content.presets).forEach(([name,p]) => { const btn = document.createElement('button'); btn.className='feature-card'; btn.type='button'; btn.innerHTML = `
${name}
Preset theme with tuned contrast and accent balance.`; btn.addEventListener('click', ()=>applyPreset(name)); root.appendChild(btn); }); }
      function toggleThemeDrawer(force){ const open = typeof force === 'boolean' ? force : !$('#themeDrawer').classList.contains('active'); $('#themeDrawer').classList.toggle('active', open); }
      function bindUI(){ $('#openPaletteBtn').addEventListener('click', ()=>togglePalette(true)); $('#openThemeBtn').addEventListener('click', ()=>toggleThemeDrawer(true)); $('#closeThemeBtn').addEventListener('click', ()=>toggleThemeDrawer(false)); $('#paletteInput').addEventListener('input', e => renderPaletteResults(e.target.value)); document.addEventListener('keydown', e => { if((e.metaKey || e.ctrlKey) && e.key.toLowerCase()==='k'){ e.preventDefault(); togglePalette(); } if(e.key==='Escape'){ togglePalette(false); toggleThemeDrawer(false); $('#quickView').classList.remove('active'); } }); $$('[data-action="clone"]').forEach(btn => btn.addEventListener('click', ()=>openQuickView('
Clone this system
You can split the single-file structure into partials, components, or routes later. The config-first naming scheme is designed for migration.'))); }
